import React, { useState, useEffect } from 'react';
import './App.css';
import Loader from './Loader';  // Add this import

function Banner() {
    return (
        <div className="banner">
            <img src="./logo.png" alt="Logo" className="banner-logo" />
        </div>
    );
}

function App() {
    const [tokenId, setTokenId] = useState('');
    const [tokenIds, setTokenIds] = useState([]);
    const [selectedAsset, setSelectedAsset] = useState('');
    const [secondAsset, setSecondAsset] = useState('');
    const [imageUrl, setImageUrl] = useState('./face.png');
    const [fade, setFade] = useState(false);
    const [isLoading, setIsLoading] = useState(false);  // State for loading
    const rgbToCss = (rgb) => `rgb(${rgb[0]}, ${rgb[1]}, ${rgb[2]})`;



    useEffect(() => {
        fetch('/token-ids')
            .then(response => response.json())
            .then(data => setTokenIds(data.sort((a, b) => parseInt(a) - parseInt(b))))
            .catch(error => console.error('Error:', error));
    }, []);

    const fetchAsset = (newTokenId, newSelectedAsset, newSecondAsset) => {
        if (newTokenId && newSelectedAsset) {
            fetch(`/get-asset?tokenId=${newTokenId}&assetType=${newSelectedAsset}&secondAssetType=${newSecondAsset}`)
                .then(response => {
                    if (!response.ok) {
                        throw new Error('Network response was not ok');
                    }
                    return response.blob();
                })
                .then(blob => {
                    const newImageUrl = URL.createObjectURL(blob);
                    updateImageWithFade(newImageUrl);
                })
                .catch(error => {
                    console.error('Error:', error);
                    setImageUrl('./face.png');
                });

                setIsLoading(true);  // Set loading to true when starting to fetch
                fetch(`/get-asset?tokenId=${newTokenId}&assetType=${newSelectedAsset}&secondAssetType=${newSecondAsset}`)
            .then(response => {
                if (!response.ok) {
                    throw new Error('Network response was not ok');
                }
                return response.blob();
            })
            .then(blob => {
                const newImageUrl = URL.createObjectURL(blob);
                updateImageWithFade(newImageUrl);
            })
            .catch(error => {
                console.error('Error:', error);
                setImageUrl('./face.png');
            })
            .finally(() => setIsLoading(false));  // Set loading to false when done fetching
        }
    };

    const handleSecondAssetChange = event => {
        setSecondAsset(event.target.value);
        fetchAsset(tokenId, selectedAsset, event.target.value);
    };

    const updateImageWithFade = (newImageUrl) => {
        setFade(true);
        setTimeout(() => {
            setImageUrl(newImageUrl);
            setFade(false);
        }, 500);
    };

    const handleTokenChange = event => {
        setTokenId(event.target.value);
        fetchAsset(event.target.value, selectedAsset);
    };

    const handleAssetChange = event => {
        setSelectedAsset(event.target.value);
        fetchAsset(tokenId, event.target.value);
    };

    return (
        <div className="App">
            <Banner />

           <header className="App-header">
                <div className="dropdown-section">
                    <h3 className="dropdown-header">Select Ape</h3>
                    <select value={tokenId} onChange={handleTokenChange} className="dropdown">
                        <option value="">Select Token ID</option>
                        {tokenIds.map(id => <option key={id} value={id}>{id}</option>)}
                    </select>
                </div>

                <div className="dropdown-section">
                    <h3 className="dropdown-header">Outfit</h3>
                    <select value={secondAsset} onChange={handleSecondAssetChange} className="dropdown">
                        <option value="">Select</option>
                        <option value="AFA">AFA</option>
                        <option value="bape_hoodie_red">Bape Hoodie Red</option>
                        <option value="bape_hoodie_green">Bape Hoodie Green</option>
                    </select>
                </div>

                <div className="dropdown-section">
                    <h3 className="dropdown-header">First Hand</h3>
                    <select value={selectedAsset} onChange={handleAssetChange} className="dropdown">
                        <option value="">Select Asset</option>
                        <option value="cheers">cheers</option>
                        <option value="peace">peace</option>
                    </select>
                </div>


                <div id="asset-display" className={fade ? 'fade-effect' : ''}>
                    {isLoading ? <Loader /> : (
                        imageUrl && <img src={imageUrl} alt="Ape" />
                    )}
                </div>
            </header>
        </div>
    );
}

export default App;
